import sqlite3

def query_customers(conn, filters: dict):
    """filters may contain any of: status, city, signup_year"""
    clauses = []
    params = []

    if filters.get("status") is not None:
        clauses.append("status = ?")
        params.append(filters["status"])

    if filters.get("city") is not None:
        clauses.append("city = ?")
        params.append(filters["city"])

    if filters.get("signup_year") is not None:
        clauses.append("strftime('%Y', signup_date) = ?")
        params.append(str(filters["signup_year"]))

    sql = "SELECT * FROM customers"
    if clauses:
        sql += " WHERE " + " AND ".join(clauses)

    cur = conn.execute(sql, params)
    return cur.fetchall()


